export default {
  name: 'AnnouncementManagement',
  data() {
    return {
      announcementList: [],
      total: 0,
      pageSize: 10,
      currentPage: 1,
      dialogVisible: false,
      dialogTitle: '',
      form: {
        id: null,
        content: '',
        status: 1,
        sortOrder: 0
      }
    }
  },
  created() {
    this.loadAnnouncementList();
  },
  methods: {
    // 加载公告列表
    async loadAnnouncementList() {
      try {
        const res = await this.$http.get('/api/announcement/list');
        if (res.code === 200) {
          this.announcementList = res.content;
          this.total = res.content.length;
        }
      } catch (error) {
        console.error('加载公告列表失败:', error);
      }
    },

    // 刷新列表
    refreshList() {
      this.loadAnnouncementList();
    },

    // 新增公告
    handleAdd() {
      this.dialogTitle = '新增公告';
      this.form = {
        id: null,
        content: '',
        status: 1,
        sortOrder: 0
      };
      this.dialogVisible = true;
    },

    // 编辑公告
    handleEdit(row) {
      this.dialogTitle = '编辑公告';
      this.form = {
        id: row.id,
        content: row.content,
        status: row.status,
        sortOrder: row.sortOrder
      };
      this.dialogVisible = true;
    },

    // 删除公告
    handleDelete(row) {
      this.$confirm('确认删除该公告？', '提示', {
        confirmButtonText: '确定',
        cancelButtonText: '取消',
        type: 'warning'
      }).then(async () => {
        try {
          const res = await this.$http.delete(`/api/announcement/${row.id}`);
          if (res.code === 200) {
            this.$message.success('删除成功');
            this.loadAnnouncementList();
          }
        } catch (error) {
          console.error('删除公告失败:', error);
          this.$message.error('删除失败');
        }
      }).catch(() => {});
    },

    // 切换状态
    async toggleStatus(row) {
      try {
        const newStatus = row.status === 1 ? 0 : 1;
        const res = await this.$http.put(`/api/announcement/${row.id}`, {
          ...row,
          status: newStatus
        });
        if (res.code === 200) {
          this.$message.success('状态更新成功');
          this.loadAnnouncementList();
        }
      } catch (error) {
        console.error('切换状态失败:', error);
        this.$message.error('状态更新失败');
      }
    },

    // 提交表单
    async submitForm() {
      try {
        let res;
        if (this.form.id) {
          // 更新
          res = await this.$http.put(`/api/announcement/${this.form.id}`, this.form);
        } else {
          // 新增
          res = await this.$http.post('/api/announcement', this.form);
        }

        if (res.code === 200) {
          this.$message.success('操作成功');
          this.dialogVisible = false;
          this.loadAnnouncementList();
        }
      } catch (error) {
        console.error('操作失败:', error);
        this.$message.error('操作失败');
      }
    },

    // 分页变化
    handleCurrentChange(page) {
      this.currentPage = page;
    }
  }
}
